.darma-loader-uiverse-gradient-flip {
  display: inline-block;
  width: 52px;
  height: 52px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color, #6366f1), var(--loader-secondary-color, #a5b4fc));
  animation: darma-loader-uiverse-gradient-flip-squareFlip 0.96s cubic-bezier(.55,.08,.38,.97) infinite;
}
@keyframes darma-loader-uiverse-gradient-flip-squareFlip { 0% { transform: perspective(120px) rotateX(0) rotateY(0); } 50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); } 100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); } }

